-- Add phone column to customers if missing
DO $$ 
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_name = 'customers' AND column_name = 'phone'
    ) THEN
        ALTER TABLE customers ADD COLUMN phone VARCHAR(50);
    END IF;
END $$;

-- Fix other messages table columns
ALTER TABLE messages ADD COLUMN IF NOT EXISTS sender_name VARCHAR(255);
ALTER TABLE messages ADD COLUMN IF NOT EXISTS message_type VARCHAR(50) DEFAULT 'text';
ALTER TABLE messages ADD COLUMN IF NOT EXISTS direction VARCHAR(20) DEFAULT 'INCOMING';

-- Fix customers table maintenance columns
ALTER TABLE customers ADD COLUMN IF NOT EXISTS created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE customers ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP;

-- Update NULL values
UPDATE customers SET created_at = CURRENT_TIMESTAMP WHERE created_at IS NULL;
UPDATE customers SET updated_at = CURRENT_TIMESTAMP WHERE updated_at IS NULL;

-- Add UNIQUE constraint if not exists
DO $$ 
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint 
        WHERE conname = 'customers_phone_unique'
    ) THEN
        ALTER TABLE customers ADD CONSTRAINT customers_phone_unique UNIQUE (phone);
    END IF;
END $$;

-- Fix phone field length
ALTER TABLE customers ALTER COLUMN phone TYPE VARCHAR(50);
ALTER TABLE messages ALTER COLUMN sender_phone TYPE VARCHAR(50);

-- Ensure sessions table exists for state management
CREATE TABLE IF NOT EXISTS sessions (
    phone VARCHAR(50) PRIMARY KEY,
    state VARCHAR(50) NOT NULL,
    data JSONB DEFAULT '{}',
    last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- One-time cleanup of corrupted settings values
DELETE FROM settings WHERE value LIKE '{{%';

