={{ (function() { 
  var data = $('Get User Session').item.json.data || {}; 
  var companyId = data.company_id || 0; 
  var couponText = (data.coupon_text || '').replace(/'/g, "''"); 
  var messageText = $('Set Basic Data').item.json.message_text.trim();
  var couponValue = null;

  // If the message is not "skip" or empty
  if (messageText && messageText !== 'skip' && messageText !== 'skip') {
    couponValue = parseInt(messageText) || null;
  }

  var valueSQL = couponValue !== null ? couponValue : 'NULL';

  return "INSERT INTO coupons (company_id, coupon_text, coupon_value) VALUES (" + companyId + ", '" + couponText + "', " + valueSQL + "); UPDATE sessions SET state = 'IDLE', data = '{}' WHERE phone = '" + $('Set Basic Data').item.json.sender_phone + "';"; 
})() }}

